export const rspackTransformerFile = () => {
  return {
    relativePath: './config/rspack.config.ts',
    content: `import { type RspackConfigMutator } from '@teambit/rspack.modules.rspack-config-mutator';

/**
 * modifies the rspack config for the components preview bundle.
 * @see https://bit.dev/reference/rspack/rspack-config
 */
export const rspackTransformer = (
  configMutator: RspackConfigMutator
): RspackConfigMutator => configMutator;`,
  };
};
